#include <iostream>
#include <stack>
using namespace std;

struct TreeNode { int val; TreeNode* left; TreeNode* right; TreeNode(int x) : val(x), left(NULL), right(NULL) {} };

class Solution { public: int solve(TreeNode* root) { stack<TreeNode*> stk; int result = 0; while (root || !stk.empty()) { if (root) { stk.push(root); root = root->right; } else { root = stk.top()->left; stk.pop(); result = stk.top()->val; } } return result; } };

int main() { Solution solution; TreeNode root(1); root.left = new TreeNode(2); root.right = new TreeNode(3); root.left->left = new TreeNode(4); root.left->right = new TreeNode(5);
    int result = solution.solve(&root);
    cout << result << endl;
    return 0;
}
